import pytest

from solution import apply_to_each


def test_applies_builtin_to_each():
    assert apply_to_each(str.upper, ["a", "b"]) == ["A", "B"]


def test_works_with_a_lambda():
    assert apply_to_each(lambda n: n * n, [1, 2, 3]) == [1, 4, 9]


def test_works_with_a_user_function():
    def double(n):
        return n * 2

    assert apply_to_each(double, [10, 20]) == [20, 40]


def test_empty_input_returns_empty_list():
    calls = []

    def spy(x):
        calls.append(x)
        return x

    assert apply_to_each(spy, []) == []
    assert calls == [], "func must not be called for an empty sequence"


def test_returns_a_new_list_not_the_input():
    src = [1, 2, 3]
    out = apply_to_each(lambda n: n, src)
    assert out == src
    assert out is not src, "must build and return a new list"


def test_preserves_order_and_length():
    # A common mistake is to dedupe or reorder via a set; order must be kept.
    out = apply_to_each(lambda n: n % 2, [3, 3, 2, 1])
    assert out == [1, 1, 0, 1]


def test_calls_func_exactly_once_per_item():
    calls = []

    def spy(x):
        calls.append(x)
        return x

    apply_to_each(spy, [7, 8, 9])
    assert calls == [7, 8, 9], "each element must be passed to func exactly once, in order"

